async (page) => {
  // Check for and dismiss cookie consent banners
  const cookieSelectors = [
    'button:has-text("Accept all")',
    'button:has-text("Accept All")',
    'button:has-text("Got it")',
    'button:has-text("I agree")',
    'button:has-text("OK")',
    '[aria-label*="cookie" i] button',
    'form[action*="cookie"] button',
    '#L2AGLb', // Google's accept all
    'button:has-text("Reject all")',
  ];

  for (const sel of cookieSelectors) {
    const btn = page.locator(sel).first();
    if (await btn.isVisible({ timeout: 500 }).catch(() => false)) {
      await btn.click();
      console.log('Dismissed cookie banner with:', sel);
      break;
    }
  }

  // Also try generic approach for Google cookie consent
  const acceptBtn = page.locator('button').filter({ hasText: /^(Accept all|Accept All|Accept|I agree|OK|Got it)$/ }).first();
  if (await acceptBtn.isVisible({ timeout: 300 }).catch(() => false)) {
    await acceptBtn.click();
    console.log('Dismissed via generic button');
  }

  return 'Cookie check done';
}

