async (page) => {
  // Check for sign in prompts and dismiss
  const signInDismiss = page.locator('[aria-label="Close"], button:has-text("Not now"), button:has-text("Maybe later"), button:has-text("Skip")');
  const count = await signInDismiss.count();
  for (let i = 0; i < count; i++) {
    if (await signInDismiss.nth(i).isVisible({ timeout: 500 }).catch(() => false)) {
      await signInDismiss.nth(i).click();
      console.log('Dismissed prompt');
      await page.waitForTimeout(500);
    }
  }

  // Try zoom in with the button
  const zoomInBtn = page.locator('button[aria-label="Zoom in"]');
  if (await zoomInBtn.isEnabled({ timeout: 1000 }).catch(() => false)) {
    await zoomInBtn.click();
    console.log('Zoomed in');
  } else {
    console.log('Zoom in not enabled');
  }

  await page.waitForTimeout(2000);
  return 'Done';
}
